insert into public.cardforge_asset_registry (
  asset_id,
  name,
  asset_type,
  url,
  preview_url,
  status,
  access_tier,
  library_source,
  file_size_bytes,
  metadata
)
select
  asset_id,
  name,
  registry_asset_type,
  url,
  url,
  'published',
  'official',
  'official',
  file_size_bytes,
  metadata
from official_layout_assets
on conflict (asset_id) do update
set
  name = excluded.name,
  asset_type = excluded.asset_type,
  url = excluded.url,
  preview_url = excluded.preview_url,
  status = excluded.status,
  access_tier = excluded.access_tier,
  library_source = excluded.library_source,
  file_size_bytes = excluded.file_size_bytes,
  metadata = excluded.metadata;

with official_layout_assets(asset_id, name, developer_asset_type, url, file_size_bytes) as (
  values
  ('default-event-badge-theme', 'Event Badge Theme', 'templates', '/api/templates#default-event-badge-theme', 11272),
  ('default-mtg-theme', 'Arcane Creature Card', 'templates', '/api/templates#default-mtg-theme', 10930),
  ('default-name-card-theme', 'Name Card Theme', 'templates', '/api/templates#default-name-card-theme', 15375),
  ('default-obsidian-neon-card-back', 'Obsidian Neon Card Back', 'templates', '/api/templates#default-obsidian-neon-card-back', 1249),
  ('default-playing-card-theme', 'Arcane Playing Card', 'templates', '/api/templates#default-playing-card-theme', 16329),
  ('default-ttrpg-stat-sheet', 'Arcane TTRPG Stat Sheet', 'templates', '/api/templates#default-ttrpg-stat-sheet', 20141),
  ('divider-gem-center', 'Gem Center Divider', 'elementPresets', '/api/styles#divider-gem-center', 938),
  ('frame-gilded-relic-premium', 'Gilded Relic Frame', 'elementPresets', '/api/styles#frame-gilded-relic-premium', 1309),
  ('frame-mtg-rules', 'MTG Rules Frame', 'elementPresets', '/api/styles#frame-mtg-rules', 1001),
  ('frame-ttrpg-vellum-premium', 'TTRPG Vellum Frame', 'elementPresets', '/api/styles#frame-ttrpg-vellum-premium', 1153),
  ('icon-fire-relic', 'Fire Relic Icon', 'elementPresets', '/api/styles#icon-fire-relic', 394),
  ('material-arcane-forge-parchment', 'Arcane Forge Parchment', 'elementPresets', '/api/styles#material-arcane-forge-parchment', 1310),
  ('material-obsidian-gilt', 'Obsidian Gilt', 'elementPresets', '/api/styles#material-obsidian-gilt', 1009),
