insert into public.cardforge_developer_asset_submissions (
  developer_id,
  developer_email,
  asset_type,
  name,
  description,
  preview_url,
  source_url,
  source_file_size_bytes,
  source_mime_type,
  registry_asset_id,
  status,
  calculated_access_tier,
  owner_access_tier_override,
  quality_score,
  tier_decision_reason,
  decision_reason,
  positive_votes,
  negative_votes
)
select
  'cardforge-official',
  null,
  developer_asset_type,
  name,
  'Official CardForge layout/preset default seeded into continuous developer review.',
  url,
  url,
  file_size_bytes,
  'application/json',
  asset_id,
  'published',
  'official',
  'official',
  0,
  'owner_forced_official',
  'awaiting_owner_review',
  0,
  0
from official_layout_assets source
where not exists (
  select 1
  from public.cardforge_developer_asset_submissions existing
  where existing.registry_asset_id = source.asset_id
);

update public.cardforge_asset_registry registry
set developer_submission_id = submissions.id
from public.cardforge_developer_asset_submissions submissions
where submissions.registry_asset_id = registry.asset_id
  and submissions.developer_id = 'cardforge-official'
  and registry.asset_type in ('template', 'elementPreset');
